import{_ as e,o as a,c as o,ae as r}from"./chunks/framework.BeVX27ge.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"en/getting-started.md","filePath":"en/getting-started.md"}'),i={name:"en/getting-started.md"};function n(s,t,d,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><blockquote><p>From login to completing your first practice session takes only 5 minutes.</p></blockquote><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Requirement</th></tr></thead><tbody><tr><td>Browser</td><td>Latest versions of Chrome, Edge, Firefox, or Safari</td></tr><tr><td>Network</td><td>Stable internet connection</td></tr><tr><td>Device</td><td>Desktop, Laptop, Tablet (Responsive Design Supported)</td></tr><tr><td>Microphone</td><td>Optional, required for voice input</td></tr></tbody></table><h2 id="logging-in" tabindex="-1">Logging In <a class="header-anchor" href="#logging-in" aria-label="Permalink to &quot;Logging In&quot;">​</a></h2><p>AI Coach uses enterprise SSO (Single Sign-On). No additional account registration is required.</p><h3 id="login-methods" tabindex="-1">Login Methods <a class="header-anchor" href="#login-methods" aria-label="Permalink to &quot;Login Methods&quot;">​</a></h3><p>The platform supports the following SSO methods (depending on company settings):</p><ol><li><strong>Sign in with Microsoft</strong> — Click to authenticate via your corporate Microsoft account</li><li><strong>Sign in with Google</strong> — Click to authenticate via your corporate Google account</li></ol><blockquote><p>The login options displayed depend on your company&#39;s deployment environment. Some instances only provide Microsoft login.</p></blockquote><h3 id="login-flow" tabindex="-1">Login Flow <a class="header-anchor" href="#login-flow" aria-label="Permalink to &quot;Login Flow&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Platform URL → Click SSO Login → Enter Corporate Credentials → Auto-redirect to Dashboard</span></span></code></pre></div><h3 id="troubleshooting-login-issues" tabindex="-1">Troubleshooting Login Issues <a class="header-anchor" href="#troubleshooting-login-issues" aria-label="Permalink to &quot;Troubleshooting Login Issues&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Description</th><th>Solution</th></tr></thead><tbody><tr><td>Unregistered Account</td><td>Your account hasn&#39;t been added yet</td><td>Contact your admin to add your account</td></tr><tr><td>Disabled Account</td><td>&quot;Account Disabled&quot; prompt</td><td>Contact admin to check your account status</td></tr><tr><td>Auth Failed</td><td>&quot;Authentication failed, please try again&quot;</td><td>Refresh the page and retry, or clear cache</td></tr><tr><td>Too Many Requests</td><td>&quot;Too many requests, please try again later&quot;</td><td>Wait a few minutes before trying again</td></tr></tbody></table><h2 id="interface-overview" tabindex="-1">Interface Overview <a class="header-anchor" href="#interface-overview" aria-label="Permalink to &quot;Interface Overview&quot;">​</a></h2><p>After logging in, you&#39;ll see the following main areas:</p><h3 id="top-navigation-bar" tabindex="-1">Top Navigation Bar <a class="header-anchor" href="#top-navigation-bar" aria-label="Permalink to &quot;Top Navigation Bar&quot;">​</a></h3><p>The top navigation bar contains (from left to right):</p><table tabindex="0"><thead><tr><th>Element</th><th>Description</th></tr></thead><tbody><tr><td>AI Coach Logo</td><td>Click to return to the Dashboard</td></tr><tr><td>Language Switcher</td><td>Switch interface language</td></tr><tr><td>Knowledge Assistant</td><td>Open Knowledge Base Q&amp;A (requires read access)</td></tr><tr><td>Settings Icon</td><td>Enter Admin Panel (managers only)</td></tr><tr><td>Logout Icon</td><td>Log out of the system safely</td></tr></tbody></table><h3 id="main-pages" tabindex="-1">Main Pages <a class="header-anchor" href="#main-pages" aria-label="Permalink to &quot;Main Pages&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Page</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Dashboard</td><td><code>/dashboard</code></td><td>Home page, shows learning stats and recent history</td></tr><tr><td>Practice</td><td><code>/chat</code></td><td>Simulate sales conversation with AI</td></tr><tr><td>Evaluation</td><td><code>/review/:sessionId</code></td><td>View practice evaluation results</td></tr><tr><td>History</td><td><code>/practice-history</code></td><td>View all historical practice records</td></tr></tbody></table><h2 id="your-first-practice-complete-flow" tabindex="-1">Your First Practice: Complete Flow <a class="header-anchor" href="#your-first-practice-complete-flow" aria-label="Permalink to &quot;Your First Practice: Complete Flow&quot;">​</a></h2><h3 id="step-1-login-view-dashboard" tabindex="-1">Step 1: Login &amp; View Dashboard <a class="header-anchor" href="#step-1-login-view-dashboard" aria-label="Permalink to &quot;Step 1: Login &amp; View Dashboard&quot;">​</a></h3><p>Log in to view the dashboard. All stats will be 0 on first use, which is normal.</p><h3 id="step-2-start-practice" tabindex="-1">Step 2: Start Practice <a class="header-anchor" href="#step-2-start-practice" aria-label="Permalink to &quot;Step 2: Start Practice&quot;">​</a></h3><p>Click the <strong>&quot;Start Conversation&quot;</strong> button on the dashboard to enter the practice page.</p><h3 id="step-3-select-scenario" tabindex="-1">Step 3: Select Scenario <a class="header-anchor" href="#step-3-select-scenario" aria-label="Permalink to &quot;Step 3: Select Scenario&quot;">​</a></h3><p>You will see two scenario cards:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Description</th></tr></thead><tbody><tr><td>Random Persona</td><td>System generates a random customer persona for practice. Best for quick starts.</td></tr><tr><td>Custom Persona</td><td>Define specific traits for targeted scenario training.</td></tr></tbody></table><blockquote><p>We recommend selecting <strong>&quot;Random Persona&quot;</strong> for your first try.</p></blockquote><h3 id="step-4-chat-environment" tabindex="-1">Step 4: Chat Environment <a class="header-anchor" href="#step-4-chat-environment" aria-label="Permalink to &quot;Step 4: Chat Environment&quot;">​</a></h3><p>After generation, you will enter the chat interface:</p><ul><li><strong>Left</strong>: Customer profile sidebar displaying the auto-generated persona</li><li><strong>Center</strong>: Chat window to communicate with the AI</li><li><strong>Top</strong>: Timer indicating the duration of the current session</li></ul><p>Type your message in the input box and press Enter to send.</p><h3 id="step-5-end-practice" tabindex="-1">Step 5: End Practice <a class="header-anchor" href="#step-5-end-practice" aria-label="Permalink to &quot;Step 5: End Practice&quot;">​</a></h3><p>When ready to finish, click the <strong>&quot;End Conversation&quot;</strong> button in the top right.</p><h3 id="step-6-view-review" tabindex="-1">Step 6: View Review <a class="header-anchor" href="#step-6-view-review" aria-label="Permalink to &quot;Step 6: View Review&quot;">​</a></h3><p>The report takes 30 seconds to 2 minutes to generate. It includes:</p><ul><li><strong>Comprehensive Review</strong> covering overall performance and stage completions</li><li><strong>Line-by-line Feedback</strong> for detailed evaluation and recommendations</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Explore the complete features of the <a href="./dashboard.html">Dashboard</a></li><li>Learn advanced settings for <a href="./practice.html">Practice</a></li><li>Understand the metrics of the <a href="./evaluation.html">Evaluation Report</a></li></ul>',42)])])}const g=e(i,[["render",n]]);export{u as __pageData,g as default};
